#include <math.h>

#include "test.h"
#include "feature/vif_tools.h"

#define EPS (1e-6)

/* Test support function */
static int almost_equal(float a, float b)
{
    return fabsf(a - b) < EPS;
}

static bool all_elements_close(const float *x, const float *y, int n)
{
    for (int i = 0; i < n; i++) {
        if (!almost_equal(x[i], y[i])) {
            fflush(stdout);
            return false;
        }
    }

    return true;
}

